import React, { useEffect, useRef, useState } from "react";
import styled, { keyframes, css } from "styled-components";

// ===== Constants =====
const NAME = "DIBYAJYOTI";
const PERIOD = ".";
const TAGLINE = "SENIOR SOFTWARE ENGINEER · LONDON";
const FULL = NAME + PERIOD;

const PAPER = "#EFE9DC";
const RULE = "rgba(120, 110, 90, 0.18)";
const INK = "#1c1812";
const ORANGE = "#ff7a1a";
const MUTED = "#6b6f76";

// Per-letter stagger: 95ms → keeps total under ~1.7s for FULL (11 chars).
const STAGGER_MS = 95;
const TYPE_DUR_MS = 260;        // single-letter stamp animation
const TOTAL_TYPE_MS = (FULL.length - 1) * STAGGER_MS + TYPE_DUR_MS; // last letter done
const DING_MS = 200;            // carriage-return ding flash
const TAG_FADE_MS = 360;        // tagline ease-in after typing
const HOLD_MS = 480;            // brief pause after ding so eye can rest
const EXIT_MS = 550;            // paper slide-away duration

const T_DING_START = TOTAL_TYPE_MS + 20;
const T_TAG_START = TOTAL_TYPE_MS + 40;
const T_EXIT_START = T_DING_START + DING_MS + HOLD_MS;
const T_DONE = T_EXIT_START + EXIT_MS + 80;

// ===== Wrap (matches project convention: black bg fades to transparent, opacity fades) =====
const Wrap = styled.div`
  position: fixed;
  inset: 0;
  z-index: 9999;
  pointer-events: none;
  background-color: rgba(0, 0, 0, ${({ $bgOff }) => ($bgOff ? 0 : 1)});
  transition: background-color ${({ $bgMs }) => $bgMs}ms ease,
              opacity 450ms ease;
  opacity: ${({ $fade }) => ($fade ? 0 : 1)};
`;

// ===== Paper sheet that slides away =====
const slideAway = keyframes`
  0%   { transform: translateY(0)       rotate(0deg); }
  100% { transform: translateY(-110vh)  rotate(-1.2deg); }
`;

const Paper = styled.div`
  position: absolute;
  inset: 0;
  background-color: ${PAPER};
  /* Faint horizontal ruled lines (typewriter paper feel) */
  background-image: repeating-linear-gradient(
    to bottom,
    transparent 0px,
    transparent 31px,
    ${RULE} 31px,
    ${RULE} 32px
  );
  /* Subtle vignette + warmth on top of the rule pattern */
  box-shadow: inset 0 0 180px rgba(120, 95, 60, 0.18);
  overflow: hidden;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  ${({ $exit }) =>
    $exit &&
    css`
      animation: ${slideAway} ${EXIT_MS}ms cubic-bezier(0.55, 0.05, 0.55, 1.05) forwards;
    `}
`;

// Tiny paper-grain noise overlay (CSS-only — radial dots via two layered gradients).
const Grain = styled.div`
  position: absolute;
  inset: 0;
  pointer-events: none;
  opacity: 0.35;
  background-image:
    radial-gradient(rgba(60, 50, 30, 0.10) 1px, transparent 1px),
    radial-gradient(rgba(60, 50, 30, 0.06) 1px, transparent 1px);
  background-size: 3px 3px, 7px 7px;
  background-position: 0 0, 1px 2px;
  mix-blend-mode: multiply;
`;

// ===== Carriage line (thin horizontal bar tracking the cursor across the top of the name) =====
const carriageMove = keyframes`
  0%   { transform: translateX(-50%) scaleX(0);   opacity: 0; }
  5%   { opacity: 0.55; }
  95%  { transform: translateX(0)    scaleX(1);   opacity: 0.55; }
  100% { transform: translateX(0)    scaleX(1);   opacity: 0; }
`;

const Carriage = styled.div`
  position: relative;
  width: min(46vw, 620px);
  height: 1px;
  margin-bottom: 18px;
  background: ${INK};
  transform-origin: left center;
  opacity: 0;
  animation: ${carriageMove} ${TOTAL_TYPE_MS + 80}ms linear forwards;
  &::after {
    /* The carriage 'head' — a small notch at the right edge of the moving line */
    content: "";
    position: absolute;
    right: -3px;
    top: -3px;
    width: 6px;
    height: 7px;
    background: ${INK};
    border-radius: 1px;
    opacity: 0.85;
  }
`;

// ===== Letters: one row of <span>s, each stamps in with animation-delay = index * STAGGER =====
const stamp = keyframes`
  0%   {
    opacity: 0;
    transform: translateY(-10px) scale(1.32) rotate(var(--jit));
    filter: blur(0.6px);
  }
  55%  {
    opacity: 1;
    transform: translateY(2px) scale(0.94) rotate(calc(var(--jit) * 0.4));
    filter: blur(0);
  }
  100% {
    opacity: 1;
    transform: translateY(0)   scale(1)    rotate(0deg);
    filter: blur(0);
  }
`;

const LetterRow = styled.div`
  display: flex;
  align-items: baseline;
  justify-content: center;
  font-family: "Courier New", "Courier", "SF Mono", "JetBrains Mono", Menlo, monospace;
  font-weight: 700;
  font-size: clamp(40px, 9vw, 110px);
  letter-spacing: 0.06em;
  color: ${INK};
  user-select: none;
`;

const Letter = styled.span`
  display: inline-block;
  opacity: 0;
  /* Each letter gets its own jitter angle via CSS var --jit (set inline). */
  animation: ${stamp} ${TYPE_DUR_MS}ms cubic-bezier(0.2, 0.9, 0.25, 1.1) forwards;
  animation-delay: ${({ $i }) => $i * STAGGER_MS}ms;
  /* Period in the brand orange to match the rest of the curtains */
  ${({ $period }) =>
    $period &&
    css`
      color: ${ORANGE};
    `}
  /* Tiny x-axis nudge per index — typewriter ribbon slop */
  margin-left: ${({ $nudge }) => $nudge}px;
`;

// ===== Tagline =====
const tagIn = keyframes`
  0%   { opacity: 0; transform: translateY(4px); }
  100% { opacity: 1; transform: translateY(0); }
`;

const Tagline = styled.div`
  margin-top: 22px;
  font-family: "Courier New", "Courier", "SF Mono", "JetBrains Mono", Menlo, monospace;
  font-size: clamp(10px, 1.1vw, 14px);
  letter-spacing: 0.32em;
  color: ${MUTED};
  opacity: 0;
  animation: ${tagIn} ${TAG_FADE_MS}ms ease-out forwards;
  animation-delay: ${T_TAG_START}ms;
`;

// ===== Carriage-return ding flash =====
const dingFlash = keyframes`
  0%   { opacity: 0; }
  35%  { opacity: 0.72; }
  100% { opacity: 0; }
`;

const Flash = styled.div`
  position: absolute;
  inset: 0;
  background: #ffffff;
  opacity: 0;
  animation: ${dingFlash} ${DING_MS}ms ease-out forwards;
  animation-delay: ${T_DING_START}ms;
  pointer-events: none;
`;

// Deterministic jitter generator — stable angle per letter index.
const jitterFor = (i) => {
  // Pseudo-random in [-2deg, +2deg] from a small mulberry-style hash.
  let x = (i * 2654435761) >>> 0;
  x ^= x >>> 13;
  x = (x * 1597334677) >>> 0;
  const v = ((x >>> 0) % 1000) / 1000; // 0..1
  return ((v - 0.5) * 4).toFixed(2) + "deg"; // -2..+2 deg
};

// Per-letter horizontal nudge (subtle, max ±0.6px) for organic ribbon slop.
const nudgeFor = (i) => {
  let x = ((i + 7) * 1103515245 + 12345) >>> 0;
  x ^= x >>> 16;
  const v = ((x >>> 0) % 1000) / 1000;
  return ((v - 0.5) * 1.2).toFixed(2);
};

const TypewriterCurtain = ({ onFinish }) => {
  const [bgOff, setBgOff] = useState(false);
  const [fade, setFade] = useState(false);
  const [done, setDone] = useState(false);
  const [exit, setExit] = useState(false);
  const onFinishRef = useRef(onFinish);
  onFinishRef.current = onFinish;
  const BG_MS = 320;

  useEffect(() => {
    const timers = [];
    // Start paper slide-away — exit phase
    timers.push(setTimeout(() => setExit(true), T_EXIT_START));
    // Once paper has cleared, drop the underlying black bg
    timers.push(setTimeout(() => setBgOff(true), T_EXIT_START + Math.round(EXIT_MS * 0.55)));
    // Final fade of the whole wrap
    timers.push(setTimeout(() => setFade(true), T_DONE - 200));
    // Tear down + onFinish
    timers.push(
      setTimeout(() => {
        setDone(true);
        if (onFinishRef.current) onFinishRef.current();
      }, T_DONE + 250)
    );
    return () => timers.forEach(clearTimeout);
  }, []);

  if (done) return null;

  return (
    <Wrap $bgOff={bgOff} $bgMs={BG_MS} $fade={fade}>
      <Paper $exit={exit}>
        <Grain />
        <Carriage />
        <LetterRow aria-label={FULL}>
          {FULL.split("").map((ch, i) => (
            <Letter
              key={`${ch}-${i}`}
              $i={i}
              $period={ch === PERIOD}
              $nudge={nudgeFor(i)}
              style={{ "--jit": jitterFor(i) }}
            >
              {ch}
            </Letter>
          ))}
        </LetterRow>
        <Tagline>{TAGLINE}</Tagline>
        <Flash />
      </Paper>
    </Wrap>
  );
};

export default TypewriterCurtain;
